type Handler<TArgs extends unknown[]> = (...args: TArgs) => void;

export class EventEmitter<TEvents extends Record<string, unknown[]>> {
  private handlers: Map<keyof TEvents, Handler<any>[]> = new Map();

  on<K extends keyof TEvents>(name: K, handler: Handler<TEvents[K]>): void {
    const existing = this.handlers.get(name) || [];
    existing.push(handler as Handler<TEvents[K]>);
    this.handlers.set(name, existing);
  }

  emit<K extends keyof TEvents>(name: K, ...args: TEvents[K]): void {
    const handlers = this.handlers.get(name);
    if (handlers) {
      for (const handler of handlers) {
        handler(...args);
      }
    }
  }
}

class MedianStream {
  private minHeap: number[] = [];
  private maxHeap: number[] = [];

  private heapifyUpMin(index: number): void {
    while (index > 0) {
      const parentIndex = Math.floor((index - 1) / 2);
      if (this.minHeap[index] >= this.minHeap[parentIndex]) break;
      [this.minHeap[index], this.minHeap[parentIndex]] = 
        [this.minHeap[parentIndex], this.minHeap[index]];
      index = parentIndex;
    }
  }

  private heapifyDownMin(index: number): void {
    const length = this.minHeap.length;
    while (index < length) {
      let smallest = index;
      const left = 2 * index + 1;
      const right = 2 * index + 2;

      if (left < length && this.minHeap[left] < this.minHeap[smallest]) {
        smallest = left;
      }
      if (right < length && this.minHeap[right] < this.minHeap[smallest]) {
        smallest = right;
      }

      if (smallest === index) break;
      [this.minHeap[index], this.minHeap[smallest]] = 
        [this.minHeap[smallest], this.minHeap[index]];
      index = smallest;
    }
  }

  private heapifyUpMax(index: number): void {
    while (index > 0) {
      const parentIndex = Math.floor((index - 1) / 2);
      if (this.maxHeap[index] <= this.maxHeap[parentIndex]) break;
      [this.maxHeap[index], this.maxHeap[parentIndex]] = 
        [this.maxHeap[parentIndex], this.maxHeap[index]];
      index = parentIndex;
    }
  }

  private heapifyDownMax(index: number): void {
    const length = this.maxHeap.length;
    while (index < length) {
      let largest = index;
      const left = 2 * index + 1;
      const right = 2 * index + 2;

      if (left < length && this.maxHeap[left] > this.maxHeap[largest]) {
        largest = left;
      }
      if (right < length && this.maxHeap[right] > this.maxHeap[largest]) {
        largest = right;
      }

      if (largest === index) break;
      [this.maxHeap[index], this.maxHeap[largest]] = 
        [this.maxHeap[largest], this.maxHeap[index]];
      index = largest;
    }
  }

  private insertMinHeap(value: number): void {
    this.minHeap.push(value);
    this.heapifyUpMin(this.minHeap.length - 1);
  }

  private extractMin(): number {
    if (this.minHeap.length === 0) throw new Error('Heap is empty');
    const result = this.minHeap[0];
    this.minHeap[0] = this.minHeap[this.minHeap.length - 1];
    this.minHeap.pop();
    if (this.minHeap.length > 0) {
      this.heapifyDownMin(0);
    }
    return result;
  }

  private insertMaxHeap(value: number): void {
    this.maxHeap.push(value);
    this.heapifyUpMax(this.maxHeap.length - 1);
  }

  private extractMax(): number {
    if (this.maxHeap.length === 0) throw new Error('Heap is empty');
    const result = this.maxHeap[0];
    this.maxHeap[0] = this.maxHeap[this.maxHeap.length - 1];
    this.maxHeap.pop();
    if (this.maxHeap.length > 0) {
      this.heapifyDownMax(0);
    }
    return result;
  }

  private balance(): void {
    if (this.minHeap.length > this.maxHeap.length + 1) {
      this.maxHeap.push(this.extractMin());
      this.heapifyUpMax(this.maxHeap.length - 1);
    } else if (this.maxHeap.length > this.minHeap.length + 1) {
      this.minHeap.push(this.extractMax());
      this.heapifyUpMin(this.minHeap.length - 1);
    }
  }

  add(n: number): void {
    if (this.minHeap.length === 0 || n >= this.minHeap[0]) {
      this.insertMinHeap(n);
    } else {
      this.insertMaxHeap(n);
    }
    this.balance();
  }

  median(): number {
    if (this.minHeap.length === 0 && this.maxHeap.length === 0) {
      throw new Error('No elements in stream');
    }

    if (this.minHeap.length === this.maxHeap.length) {
      return (this.minHeap[0] + this.maxHeap[0]) / 2;
    } else if (this.minHeap.length > this.maxHeap.length) {
      return this.minHeap[0];
    } else {
      return this.maxHeap[0];
    }
  }
